#include <iostream>
using namespace std;

class Player {
private:
    string name;
    int hp;
public:
    Player(string n, int h) : name(n), hp(h) {}

    void attack() const {
        cout << name << " attacks!" << endl;
    }
    string getName() const { return name; }
    int getHp() const { return hp; }

    void takeDamage(int dmg) {
        hp = max(0, hp - dmg);
    }
};

Player p("Neo", 100);
p.attack();  // Neo attacks!
p.takeDamage(30);
cout << p.getHp(); // 70

// struct: default public
struct Point {
    int x, y;  // public by default
};
