// class: default private
class Circle {
    double radius;  // private by default!
public:
    Circle(double r) : radius(r) {}
    double area() const {
        return 3.14159 * radius * radius;
    }
};

class Engine {
    const int cylinders;  // const — MUST use init list
    int rpm;
    string brand;
public:
    // Member initializer list:
    Engine(int cyl, string b)
        : cylinders(cyl), rpm(0), brand(b) {
        // body runs AFTER initialization
        cout << brand << " engine ready" << endl;
    }

    // const method — doesn't modify *this:
    int getCylinders() const { return cylinders; }

    // Non-const — modifies state:
    void rev(int r) { rpm = r; }
};

