#include <iostream>
using namespace std;

class FileWrapper {
    FILE* fp;
public:
    FileWrapper(const char* name, const char* mode) {
        fp = fopen(name, mode);
        cout << "File opened" << endl;
    }

    // Destructor — auto-called when wrapper goes out of scope:
    ~FileWrapper() {
        if(fp) fclose(fp);
        cout << "File closed automatically" << endl;
    }

    void write(const char* s) {
        if(fp) fputs(s, fp);
    }
};

void saveData() {
    FileWrapper f("out.txt", "w"); // opens
    f.write("Hello!");
}   // <-- destructor auto-called here! File closed!

#include <memory>
using namespace std;

void example() {
    // raw pointer: YOU must delete:
    int* raw = new int(42);
    delete raw;  // easy to forget!

    // unique_ptr: auto-deleted at scope end:
    unique_ptr<int> smart = make_unique<int>(42);
    cout << *smart << endl;  // 42
}   // <-- smart auto-deleted here!
    // No delete needed — RAII handles it!

