#include <iostream>
using namespace std;

struct Vec2 {
    float x, y;
    Vec2(float x, float y) : x(x), y(y) {}

    // operator+:
    Vec2 operator+(const Vec2& o) const {
        return Vec2(x+o.x, y+o.y);
    }

    // operator== :
    bool operator==(const Vec2& o) const {
        return x==o.x && y==o.y;
    }

    // operator<< (friend for cout):
    friend ostream& operator<<(ostream& os,
                               const Vec2& v) {
        return os << '(' << v.x << ',' << v.y << ')';
    }
};

Vec2 a(1,2), b(3,4);
Vec2 c = a + b;
cout << c << endl;    // (4,6)
cout << (a==b);       // 0 (false)

